    29→import org.semanticweb.owlapi.model.AsOWLClass;
    30→import org.semanticweb.owlapi.model.OWLClass;
    31→import org.semanticweb.owlapi.model.OWLClassExpression;
    32→import org.semanticweb.owlapi.model.OWLDataFactory;
    33→import org.semanticweb.owlapi.model.OWLDataProperty;
    34→import org.semanticweb.owlapi.model.OWLDataRestriction;
    35→import org.semanticweb.owlapi.model.OWLDatatype;
    36→import org.semanticweb.owlapi.model.OWLEntity;
    37→import org.semanticweb.owlapi.model.OWLLiteral;
    38→import org.semanticweb.owlapi.model.OWLNamedIndividual;
    39→import org.semanticweb.owlapi.model.OWLObjectProperty;
    40→import org.semanticweb.owlapi.model.OWLOntology;
    41→import org.semanticweb.owlapi.model.OWLSubClassOfAxiom;
    42→import org.semanticweb.owlapi.search.EntitySearcher;
    43→
    44→public class ResourceSchemaMapper {
    45→  private static final Logger logger = Logger.getLogger(ResourceSchemaMapper.class.getName());
    46→  private final MappingContext context;
    47→  private final PropertyNameResolver nameResolver = new PropertyNameResolver();
    48→  private final String type;
    49→  private final OWLClass cls;
    50→  private final String classDescription;
    51→  private final String name;
    52→  private final Schema<?> schema;
    53→
    54→  public Schema<?> getSchema() {
    55→    return schema;
    56→  }
    57→
    58→  public String getName() {
    59→    return name;
    60→  }
    61→
    62→  public ResourceSchemaMapper(MappingContext context, OWLClass cls, String clsDescription) {
    63→    this.context = context;
    64→    this.cls = cls;
    65→    this.classDescription = clsDescription;
    66→    this.type = "object";
    67→    this.name = nameResolver.resolve(cls);
    68→    this.schema = createSchema(cls);
    69→  }
    70→
    71→  /**
    72→   * Read the Ontology and gets all the Class restrictions on object or data properties and generate
    73→   * SchemaProperties.
    74→   *
    75→   * @param analyzedClass Class that will be analyzed in order to get its restrictions
    76→   */
    77→  private Schema createSchema(OWLClass analyzedClass) {
    78→    // Is always an ObjectSchema - create here
    79→    Schema<?> resourceSchema = new ObjectSchema();
    80→    resourceSchema.setSpecVersion(SpecVersion.V31);
    81→    resourceSchema.setName(this.name);
    82→    resourceSchema.setDescription(this.classDescription);
    83→    resourceSchema.setType(this.type);
    84→    resourceSchema.setAdditionalProperties(false);
    85→    resourceSchema.setTitle(getLabel(this.cls));
    86→
    87→    OWLDataFactory dataFactory = context.getManager().getOWLDataFactory();
    88→    OWLClass owlThing = dataFactory.getOWLThing();
    89→    SchemaVisitor objectSchemaVisitor;
    90→    SchemaVisitor dataSchemaVisitor;
    91→
    92→    objectSchemaVisitor = new SchemaVisitor(analyzedClass, context.getOntology(), owlThing, "", false);
    93→    dataSchemaVisitor = new SchemaVisitor(analyzedClass, context.getOntology(), owlThing, "", false);
    94→
    95→    OWLOntology ontology = context.getOntology();
    96→    String schemaLabel = context.getSchemaLabel();
    97→    List<OWLSubClassOfAxiom> taxonomyAx = getTaxonomyAxioms(analyzedClass);
    98→    List<OWLSubClassOfAxiom> subClassOfAxioms = ontology.subClassAxiomsForSubClass(analyzedClass).toList();
    99→    List<OWLSubClassOfAxiom> superClassOfAxioms = getSuperClassAxioms(analyzedClass, null).toList();
   100→
   101→    subClassOfAxioms.stream().filter(owlSubClassOfAxiom -> !taxonomyAx.contains(owlSubClassOfAxiom))
   102→        .filter(WithAnnotation.of(OntologyConstants.apiLabel, schemaLabel)).map(OWLSubClassOfAxiom::getSuperClass)
   103→        .forEach(superClass -> {
   104→          if (!superClass.getObjectPropertiesInSignature().isEmpty()) {
   105→            superClass.accept(objectSchemaVisitor);
   106→          }
   107→          if (!superClass.getDataPropertiesInSignature().isEmpty()) {
   108→            superClass.accept(dataSchemaVisitor);
   109→          }
   110→        });
   111→
   112→    superClassOfAxioms.stream().map(OWLSubClassOfAxiom::getSuperClass).forEach(superCls -> {
   113→      if (!superCls.getObjectPropertiesInSignature().isEmpty()) {
   114→        superCls.accept(objectSchemaVisitor);
   115→      }
   116→      if (!superCls.getDataPropertiesInSignature().isEmpty()) {
   117→        superCls.accept(dataSchemaVisitor);
   118→      }
   119→    });
   120→
   121→    // Merge typed restrictions from both visitors
   122→    Map<String, Set<RestrictionInfo>> restrictions = new HashMap<>();
   123→    Stream.of(objectSchemaVisitor, dataSchemaVisitor)
   124→        .map(SchemaVisitor::getRestrictions)
   125→        .flatMap(map -> map.entrySet().stream())
   126→        .forEach(entry -> restrictions.computeIfAbsent(entry.getKey(), k -> new LinkedHashSet<>())
   127→            .addAll(entry.getValue()));
   128→
   129→    // Get typed range Multimaps
   130→    Multimap<String, OWLClass> objectPropertyRanges = objectSchemaVisitor.getObjectPropertyRanges();
   131→    Multimap<String, OWLDatatype> dataPropertyRanges = dataSchemaVisitor.getDataPropertyRanges();
   132→
   133→    // Get data property names from visitor (all properties encountered in restrictions)
   134→    Set<String> dataPropertyNames = dataSchemaVisitor.getDataPropertyNames();
   135→
   136→    for (String dataPropertyName : dataPropertyNames) {
   137→      // Find the OWLDataProperty from the ontology
   138→      Optional<OWLDataProperty> dataPropertyOpt = context.getOntology()
   139→          .getDataPropertiesInSignature().stream()
   140→          .filter(prop -> nameResolver.resolve(prop).equals(dataPropertyName))
   141→          .findFirst();
   142→
   143→      if (dataPropertyOpt.isEmpty()) {
   144→        continue;
   145→      }
   146→      OWLDataProperty propertyFromDataRestrictions = dataPropertyOpt.get();
   147→
   148→      String propertyDescription = OntologyUtil.getDescription(propertyFromDataRestrictions, context.getOntology());
   149→
   150→      // Extract range datatype names from typed sources
   151→      List<String> rangesDP = new ArrayList<>();
   152→      dataPropertyRanges.get(dataPropertyName).stream()
   153→          .map(nameResolver::resolve)
   154→          .forEach(rangesDP::add);
   155→
   156→      // Also extract from restrictions themselves
   157→      Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(dataPropertyName,
   158→          Set.of());
   159→      propertyRestrictions.stream()
   160→          .flatMap(r -> r.getRangeNames(nameResolver).stream())
   161→          .forEach(rangesDP::add);
   162→
   163→      // Extract enum values from DataOneOf restrictions
   164→      List<String> enumValues = propertyRestrictions.stream()
   165→          .flatMap(r -> r.getEnumValues().stream())
   166→          .toList();
   167→
   168→      // This is rather ugly, but it's the only way to get the example value from the annotation
   169→      String exampleValue =
   170→          // See if there's a specific example annotation on the restriction subclass
   171→          subClassOfAxioms.stream()
   172→              .filter(owlSubClassOfAxiom ->
   173→                  owlSubClassOfAxiom.getSuperClass() instanceof OWLDataRestriction d
   174→                      && d.getProperty()
   175→                      .asOWLDataProperty().getIRI().equals(propertyFromDataRestrictions.getIRI()))
   176→              .map(owlSubClassOfAxiom -> owlSubClassOfAxiom.getAnnotations().stream()
   177→                  .filter(annotation -> annotation.getProperty().getIRI()
   178→                      .equals(OntologyConstants.SKOS_EXAMPLE))
   179→                  .findFirst().flatMap(annotation -> annotation.mapLiteral(OWLLiteral::getLiteral)))
   180→              .flatMap(Optional::stream).findFirst()
   181→              // Default to the annotation on the data property itself, otherwise default to null here
   182→              .orElse(OntologyUtil.defaultAnnotationsOf(propertyFromDataRestrictions,
   183→                      context.getOntology())
   184→                  .getOrDefault(OntologyConstants.SKOS_EXAMPLE.getShortForm(), null));
   185→      String label = getLabel(propertyFromDataRestrictions);
   186→      DataPropertyMapper mapperDataProperty = new DataPropertyMapper(
   187→          context.getConfig(),
   188→          nameResolver.resolve(propertyFromDataRestrictions),
   189→          label,
   190→          propertyDescription,
   191→          exampleValue,
   192→          propertyRestrictions,
   193→          enumValues,  // valuesFromDataRestrictions_ranges
   194→          rangesDP);    // type
   195→      try {
   196→        resourceSchema.addProperty(mapperDataProperty.getName(),
   197→            mapperDataProperty.getSchemaByDataProperty());
   198→        if (mapperDataProperty.isRequired()) {
   199→          resourceSchema.addRequiredItem(mapperDataProperty.getName());
   200→        }
   201→      } catch (Exception e) {
   202→        throw new RuntimeException(
   203→            "Error when processing data property " + mapperDataProperty.getName(), e);
   204→      }
   205→    }
   206→
   207→    // Get object property names from visitor (all properties encountered in restrictions)
   208→    Set<String> objectPropertyNames = objectSchemaVisitor.getObjectPropertyNames();
   209→
   210→    for (String objectPropertyName : objectPropertyNames) {
   211→      // Find the OWLObjectProperty from the ontology
   212→      Optional<OWLObjectProperty> objectPropertyOpt = context.getOntology()
   213→          .getObjectPropertiesInSignature().stream()
   214→          .filter(prop -> nameResolver.resolve(prop).equals(objectPropertyName))
   215→          .findFirst();
   216→
   217→      if (objectPropertyOpt.isEmpty()) {
   218→        continue;
   219→      }
   220→      OWLObjectProperty propertyFromObjectRestrictions = objectPropertyOpt.get();
   221→
   222→      // Extract range class names from typed sources
   223→      List<String> rangesOP = new ArrayList<>();
   224→      objectPropertyRanges.get(objectPropertyName).stream()
   225→          .map(nameResolver::resolve)
   226→          .forEach(rangesOP::add);
   227→
   228→      // Also extract from restrictions themselves
   229→      Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(objectPropertyName,
   230→          Set.of());
   231→      propertyRestrictions.stream()
   232→          .flatMap(r -> r.getRangeNames(nameResolver).stream())
   233→          .forEach(rangesOP::add);
   234→
   235→      // Remove duplicates to avoid treating single-range properties as multi-range
   236→      rangesOP = rangesOP.stream().distinct().toList();
   237→
   238→      ObjectPropertyMapper mapperObjectProperty;
   239→      String propertyDescription = OntologyUtil.getDescription(propertyFromObjectRestrictions, context.getOntology());
   240→      String propertyLabel = getLabel(propertyFromObjectRestrictions);
   241→      mapperObjectProperty = new ObjectPropertyMapper(context, objectPropertyName, propertyLabel,
   242→          propertyDescription, propertyRestrictions, rangesOP);
   243→      resourceSchema.addProperty(mapperObjectProperty.getName(), mapperObjectProperty.getSchema());
   244→      if (mapperObjectProperty.isRequired())
   245→        resourceSchema.addRequiredItem(mapperObjectProperty.getName());
   246→    }
   247→
   248→    Set<OWLObjectProperty> taxonomyPropertyNames = taxonomyAx.stream().map(OWLSubClassOfAxiom::getSuperClass)
   249→        .flatMap(superCls -> superCls.getObjectPropertiesInSignature().stream()).collect(Collectors.toSet());
   250→
   251→    for (OWLObjectProperty taxonomyProperty : taxonomyPropertyNames) {
   252→      for (OWLSubClassOfAxiom ax : taxonomyAx) {
   253→        Set<RestrictionInfo> taxonomyRestrictions = new LinkedHashSet<>();
   254→        OWLClassExpression superCls = ax.getSuperClass();
   255→        for (OWLObjectProperty objectProperty : superCls.getObjectPropertiesInSignature()) {
   256→
   257→          if (objectProperty.equals(taxonomyProperty)) {
   258→            Set<OWLNamedIndividual> individualsInSignature = superCls.getIndividualsInSignature();
   259→            RestrictionInfo.from(superCls).ifPresent(taxonomyRestrictions::add);
   260→            TaxonomyPropertyMapper taxonomyPropertyMapper;
   261→            if (!individualsInSignature.isEmpty()) {
   262→              taxonomyPropertyMapper = new TaxonomyPropertyMapper(context,
   263→                  nameResolver.resolve(taxonomyProperty),
   264→                  OntologyUtil.getDescription(cls, context.getOntology()),
   265→                  getLabel(taxonomyProperty), individualsInSignature.stream()
   266→                  .map(this::getLabel)
   267→                  .toList(), taxonomyRestrictions);
   268→              resourceSchema.addProperty(taxonomyPropertyMapper.getName(), taxonomyPropertyMapper.getTaxonomySchemaObject());
   269→              if (taxonomyPropertyMapper.isRequired())
   270→                resourceSchema.addRequiredItem(taxonomyPropertyMapper.getName());
   271→            } else {
   272→              Set<OWLClass> classesInSignature = superCls.getClassesInSignature();
   273→              for (OWLClass cls : classesInSignature) {
   274→                List<OWLNamedIndividual> individuals = EntitySearcher.getIndividuals(cls, context.getOntology())
   275→                    .flatMap(Narrow.to(OWLNamedIndividual.class)).toList();
   276→                taxonomyPropertyMapper = new TaxonomyPropertyMapper(context,
   277→                    taxonomyName(nameResolver.resolve(cls)),
   278→                    OntologyUtil.getDescription(cls, context.getOntology()), getLabel(cls),
   279→                    individuals.stream()
   280→                        .map(this::getLabel).toList(), taxonomyRestrictions);
   281→                resourceSchema.addProperty(taxonomyPropertyMapper.getName(),
   282→                    taxonomyPropertyMapper.getTaxonomySchemaObject());
   283→                if (taxonomyPropertyMapper.isRequired())
   284→                  resourceSchema.addRequiredItem(taxonomyPropertyMapper.getName());
   285→              }
   286→            }
   287→          }
   288→        }
   289→      }
   290→    }
   291→    if (resourceSchema.getProperties() == null || resourceSchema.getProperties().isEmpty()) {
   292→      logger.warning("No properties with " + OntologyConstants.apiLabel + " annotation found for: " + analyzedClass);
   293→      List<OWLSubClassOfAxiom> all = Stream.of(superClassOfAxioms, subClassOfAxioms, taxonomyAx)
   294→          .flatMap(Collection::stream).toList();
   295→      if (!all.isEmpty()) {
   296→        List<String> possible = all.stream()
   297→            .map(owlSubClassOfAxiom -> owlSubClassOfAxiom.getSuperClass().toString()).toList();
   298→        if (!possible.isEmpty()) {
   299→          possible.forEach(s -> logger.warning("\tPossible property: " + s));
   300→        }
   301→      }
   302→    }
   303→    return resourceSchema;
   304→  }
   305→
   306→  private List<OWLSubClassOfAxiom> getTaxonomyAxioms(OWLClass analyzedClass) {
   307→    Set<OWLSubClassOfAxiom> subAx = context.getOntology().getSubClassAxiomsForSubClass(analyzedClass);
   308→    String schemaAnnotation = getSchemaAnnotation(context.getSchemaLabel());
   309→
   310→    return subAx.stream().filter(ax -> ax.annotations()
   311→        .anyMatch(annotation -> annotation.getValue().toString().equals(schemaAnnotation))).filter(ax -> {
   312→      OWLClassExpression superCls = ax.getSuperClass();
   313→      return !superCls.getObjectPropertiesInSignature().isEmpty() && (superCls.individualsInSignature()
   314→          .anyMatch(individual -> !EntitySearcher.getObjectPropertyValues(individual, context.getOntology())
   315→              .isEmpty()) || superCls.classesInSignature()
   316→          .anyMatch(cls -> EntitySearcher.getIndividuals(cls, context.getOntology()).findAny().isPresent()));
   317→    }).collect(Collectors.toList());
   318→  }
   319→
   320→  public String getSchemaName() {
   321→    return nameResolver.resolve(cls);
   322→  }
   323→
   324→  private String getSchemaAnnotation(String schema) {
   325→    return '"' + schema + '"' + "^^xsd:string";
   326→  }
   327→
   328→  private String taxonomyName(String taxonomy_name) {
   329→    if (StringUtils.countMatches(taxonomy_name, "_") > 0) {
   330→      return taxonomy_name.substring(taxonomy_name.lastIndexOf("_") + 1);
   331→    }
   332→    return taxonomy_name.substring(0, 1).toUpperCase() + taxonomy_name.substring(1);
   333→  }
   334→
   335→  private String getLabel(final OWLEntity entity) {
   336→    return OntologyUtil.getTitle(entity, context.getOntology());
   337→  }
   338→
   339→  private Stream<OWLSubClassOfAxiom> getSuperClassAxioms(OWLClass analyzedClass,
   340→                                                         @Nullable Set<OWLClass> ignoreClasses) {
   341→    final Set<OWLClass> processedClasses = Optional.ofNullable(ignoreClasses).orElse(new HashSet<OWLClass>());
   342→    final String schemaAnnotation = getSchemaAnnotation(context.getSchemaLabel());
   343→    return context.getOntology().subClassAxiomsForSubClass(analyzedClass)
   344→        .filter(WithAnnotation.of(OntologyConstants.apiLabel, context.getSchemaLabel()))
   345→        .map(OWLSubClassOfAxiom::getSuperClass).filter(OWLClassExpression::isOWLClass).map(AsOWLClass::asOWLClass)
   346→        .filter(Predicate.not(processedClasses::contains)).peek(processedClasses::add) // side effect
   347→        .flatMap(context.getOntology()::subClassAxiomsForSubClass).flatMap(owlSubClassOfAxiom -> {
   348→          final OWLClassExpression superClass = owlSubClassOfAxiom.getSuperClass();
   349→          final List<OWLSubClassOfAxiom> superClassAxioms = new ArrayList<>();
   350→          if (superClass.isOWLClass()) {
   351→            getSuperClassAxioms(superClass.asOWLClass(), processedClasses).forEach(superClassAxioms::add);
   352→          }
   353→          if (owlSubClassOfAxiom.annotations()
   354→              .anyMatch(owlAnnotation -> owlAnnotation.getValue().toString().equals(schemaAnnotation))) {
   355→            superClassAxioms.add(owlSubClassOfAxiom);
   356→          }
   357→          return superClassAxioms.stream();
   358→        });
   359→  }
   360→
   361→}
   362→

