package com.grl.component.mapper;

import com.google.common.collect.Multimap;
import com.grl.component.asg.OntologyConstants;
import com.grl.component.owl.Narrow;
import com.grl.component.owl.OntologyUtil;
import com.grl.component.owl.WithAnnotation;
import com.grl.component.schema.PropertyNameResolver;
import com.grl.component.schema.RestrictionInfo;
import com.grl.component.schema.SchemaVisitor;
import io.swagger.v3.oas.models.SpecVersion;
import io.swagger.v3.oas.models.media.ObjectSchema;
import io.swagger.v3.oas.models.media.Schema;
import java.util.ArrayList;
import java.util.Collection;
import java.util.HashMap;
import java.util.HashSet;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.Set;
import java.util.function.Predicate;
import java.util.logging.Logger;
import java.util.stream.Collectors;
import java.util.stream.Stream;
import javax.annotation.Nullable;
import org.apache.commons.lang3.StringUtils;
import org.semanticweb.owlapi.model.AsOWLClass;
import org.semanticweb.owlapi.model.OWLClass;
import org.semanticweb.owlapi.model.OWLClassExpression;
import org.semanticweb.owlapi.model.OWLDataFactory;
import org.semanticweb.owlapi.model.OWLDataProperty;
import org.semanticweb.owlapi.model.OWLDataRestriction;
import org.semanticweb.owlapi.model.OWLDatatype;
import org.semanticweb.owlapi.model.OWLEntity;
import org.semanticweb.owlapi.model.OWLLiteral;
import org.semanticweb.owlapi.model.OWLNamedIndividual;
import org.semanticweb.owlapi.model.OWLObjectProperty;
import org.semanticweb.owlapi.model.OWLOntology;
import org.semanticweb.owlapi.model.OWLSubClassOfAxiom;
import org.semanticweb.owlapi.search.EntitySearcher;

public class ResourceSchemaMapper {
  private static final Logger logger = Logger.getLogger(ResourceSchemaMapper.class.getName());
  private final MappingContext context;
  private final PropertyNameResolver nameResolver = new PropertyNameResolver();
  private final String type;
  private final OWLClass cls;
  private final String classDescription;
  private final String name;
  private final Schema<?> schema;

  public Schema<?> getSchema() {
    return schema;
  }

  public String getName() {
    return name;
  }

  public ResourceSchemaMapper(MappingContext context, OWLClass cls, String clsDescription) {
    this.context = context;
    this.cls = cls;
    this.classDescription = clsDescription;
    this.type = "object";
    this.name = nameResolver.resolve(cls);
    this.schema = createSchema(cls);
  }

  /**
   * Read the Ontology and gets all the Class restrictions on object or data properties and generate
   * SchemaProperties.
   *
   * @param analyzedClass Class that will be analyzed in order to get its restrictions
   */
  private Schema createSchema(OWLClass analyzedClass) {
    // Is always an ObjectSchema - create here
    Schema<?> resourceSchema = new ObjectSchema();
    resourceSchema.setSpecVersion(SpecVersion.V31);
    resourceSchema.setName(this.name);
    resourceSchema.setDescription(this.classDescription);
    resourceSchema.setType(this.type);
    resourceSchema.setAdditionalProperties(false);
    resourceSchema.setTitle(getLabel(this.cls));

    OWLDataFactory dataFactory = context.getManager().getOWLDataFactory();
    OWLClass owlThing = dataFactory.getOWLThing();
    SchemaVisitor objectSchemaVisitor;
    SchemaVisitor dataSchemaVisitor;

    objectSchemaVisitor = new SchemaVisitor(analyzedClass, context.getOntology(), owlThing, "", false);
    dataSchemaVisitor = new SchemaVisitor(analyzedClass, context.getOntology(), owlThing, "", false);

    OWLOntology ontology = context.getOntology();
    String schemaLabel = context.getSchemaLabel();
    List<OWLSubClassOfAxiom> taxonomyAx = getTaxonomyAxioms(analyzedClass);
    List<OWLSubClassOfAxiom> subClassOfAxioms = ontology.subClassAxiomsForSubClass(analyzedClass).toList();
    List<OWLSubClassOfAxiom> superClassOfAxioms = getSuperClassAxioms(analyzedClass, null).toList();

    subClassOfAxioms.stream().filter(owlSubClassOfAxiom -> !taxonomyAx.contains(owlSubClassOfAxiom))
        .filter(WithAnnotation.of(OntologyConstants.apiLabel, schemaLabel)).map(OWLSubClassOfAxiom::getSuperClass)
        .forEach(superClass -> {
          if (!superClass.getObjectPropertiesInSignature().isEmpty()) {
            superClass.accept(objectSchemaVisitor);
          }
          if (!superClass.getDataPropertiesInSignature().isEmpty()) {
            superClass.accept(dataSchemaVisitor);
          }
        });

    superClassOfAxioms.stream().map(OWLSubClassOfAxiom::getSuperClass).forEach(superCls -> {
      if (!superCls.getObjectPropertiesInSignature().isEmpty()) {
        superCls.accept(objectSchemaVisitor);
      }
      if (!superCls.getDataPropertiesInSignature().isEmpty()) {
        superCls.accept(dataSchemaVisitor);
      }
    });

    // Merge typed restrictions from both visitors
    Map<String, Set<RestrictionInfo>> restrictions = new HashMap<>();
    Stream.of(objectSchemaVisitor, dataSchemaVisitor)
        .map(SchemaVisitor::getRestrictions)
        .flatMap(map -> map.entrySet().stream())
        .forEach(entry -> restrictions.computeIfAbsent(entry.getKey(), k -> new LinkedHashSet<>())
            .addAll(entry.getValue()));

    // Get typed range Multimaps
    Multimap<String, OWLClass> objectPropertyRanges = objectSchemaVisitor.getObjectPropertyRanges();
    Multimap<String, OWLDatatype> dataPropertyRanges = dataSchemaVisitor.getDataPropertyRanges();

    // Get data property names from visitor (all properties encountered in restrictions)
    Set<String> dataPropertyNames = dataSchemaVisitor.getDataPropertyNames();

    for (String dataPropertyName : dataPropertyNames) {
      // Find the OWLDataProperty from the ontology
      Optional<OWLDataProperty> dataPropertyOpt = context.getOntology()
          .getDataPropertiesInSignature().stream()
          .filter(prop -> nameResolver.resolve(prop).equals(dataPropertyName))
          .findFirst();

      if (dataPropertyOpt.isEmpty()) {
        continue;
      }
      OWLDataProperty propertyFromDataRestrictions = dataPropertyOpt.get();

      String propertyDescription = OntologyUtil.getDescription(propertyFromDataRestrictions, context.getOntology());

      // Extract range datatype names from typed sources
      List<String> rangesDP = new ArrayList<>();
      dataPropertyRanges.get(dataPropertyName).stream()
          .map(nameResolver::resolve)
          .forEach(rangesDP::add);

      // Also extract from restrictions themselves
      Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(dataPropertyName,
          Set.of());
      propertyRestrictions.stream()
          .flatMap(r -> r.getRangeNames(nameResolver).stream())
          .forEach(rangesDP::add);

      // Extract enum values from DataOneOf restrictions
      List<String> enumValues = propertyRestrictions.stream()
          .flatMap(r -> r.getEnumValues().stream())
          .toList();

      // This is rather ugly, but it's the only way to get the example value from the annotation
      String exampleValue =
          // See if there's a specific example annotation on the restriction subclass
          subClassOfAxioms.stream()
              .filter(owlSubClassOfAxiom ->
                  owlSubClassOfAxiom.getSuperClass() instanceof OWLDataRestriction d
                      && d.getProperty()
                      .asOWLDataProperty().getIRI().equals(propertyFromDataRestrictions.getIRI()))
              .map(owlSubClassOfAxiom -> owlSubClassOfAxiom.getAnnotations().stream()
                  .filter(annotation -> annotation.getProperty().getIRI()
                      .equals(OntologyConstants.SKOS_EXAMPLE))
                  .findFirst().flatMap(annotation -> annotation.mapLiteral(OWLLiteral::getLiteral)))
              .flatMap(Optional::stream).findFirst()
              // Default to the annotation on the data property itself, otherwise default to null here
              .orElse(OntologyUtil.defaultAnnotationsOf(propertyFromDataRestrictions,
                      context.getOntology())
                  .getOrDefault(OntologyConstants.SKOS_EXAMPLE.getShortForm(), null));
      String label = getLabel(propertyFromDataRestrictions);
      DataPropertyMapper mapperDataProperty = new DataPropertyMapper(
          context.getConfig(),
          nameResolver.resolve(propertyFromDataRestrictions),
          label,
          propertyDescription,
          exampleValue,
          propertyRestrictions,
          enumValues,  // valuesFromDataRestrictions_ranges
          rangesDP);    // type
      try {
        resourceSchema.addProperty(mapperDataProperty.getName(),
            mapperDataProperty.getSchemaByDataProperty());
        if (mapperDataProperty.isRequired()) {
          resourceSchema.addRequiredItem(mapperDataProperty.getName());
        }
      } catch (Exception e) {
        throw new RuntimeException(
            "Error when processing data property " + mapperDataProperty.getName(), e);
      }
    }

    // Get object property names from visitor (all properties encountered in restrictions)
    Set<String> objectPropertyNames = objectSchemaVisitor.getObjectPropertyNames();

    for (String objectPropertyName : objectPropertyNames) {
      // Find the OWLObjectProperty from the ontology
      Optional<OWLObjectProperty> objectPropertyOpt = context.getOntology()
          .getObjectPropertiesInSignature().stream()
          .filter(prop -> nameResolver.resolve(prop).equals(objectPropertyName))
          .findFirst();

      if (objectPropertyOpt.isEmpty()) {
        continue;
      }
      OWLObjectProperty propertyFromObjectRestrictions = objectPropertyOpt.get();

      // Extract range class names from typed sources
      List<String> rangesOP = new ArrayList<>();
      objectPropertyRanges.get(objectPropertyName).stream()
          .map(nameResolver::resolve)
          .forEach(rangesOP::add);

      // Also extract from restrictions themselves
      Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(objectPropertyName,
          Set.of());
      propertyRestrictions.stream()
          .flatMap(r -> r.getRangeNames(nameResolver).stream())
          .forEach(rangesOP::add);

      // Remove duplicates to avoid treating single-range properties as multi-range
      rangesOP = rangesOP.stream().distinct().toList();

      ObjectPropertyMapper mapperObjectProperty;
      String propertyDescription = OntologyUtil.getDescription(propertyFromObjectRestrictions, context.getOntology());
      String propertyLabel = getLabel(propertyFromObjectRestrictions);
      mapperObjectProperty = new ObjectPropertyMapper(context, objectPropertyName, propertyLabel,
          propertyDescription, propertyRestrictions, rangesOP);
      resourceSchema.addProperty(mapperObjectProperty.getName(), mapperObjectProperty.getSchema());
      if (mapperObjectProperty.isRequired())
        resourceSchema.addRequiredItem(mapperObjectProperty.getName());
    }

    Set<OWLObjectProperty> taxonomyPropertyNames = taxonomyAx.stream().map(OWLSubClassOfAxiom::getSuperClass)
        .flatMap(superCls -> superCls.getObjectPropertiesInSignature().stream()).collect(Collectors.toSet());

    for (OWLObjectProperty taxonomyProperty : taxonomyPropertyNames) {
      for (OWLSubClassOfAxiom ax : taxonomyAx) {
        Set<RestrictionInfo> taxonomyRestrictions = new LinkedHashSet<>();
        OWLClassExpression superCls = ax.getSuperClass();
        for (OWLObjectProperty objectProperty : superCls.getObjectPropertiesInSignature()) {

          if (objectProperty.equals(taxonomyProperty)) {
            Set<OWLNamedIndividual> individualsInSignature = superCls.getIndividualsInSignature();
            RestrictionInfo.from(superCls).ifPresent(taxonomyRestrictions::add);
            TaxonomyPropertyMapper taxonomyPropertyMapper;
            if (!individualsInSignature.isEmpty()) {
              taxonomyPropertyMapper = new TaxonomyPropertyMapper(context,
                  nameResolver.resolve(taxonomyProperty),
                  OntologyUtil.getDescription(cls, context.getOntology()),
                  getLabel(taxonomyProperty), individualsInSignature.stream()
                  .map(this::getLabel)
                  .toList(), taxonomyRestrictions);
              resourceSchema.addProperty(taxonomyPropertyMapper.getName(), taxonomyPropertyMapper.getTaxonomySchemaObject());
              if (taxonomyPropertyMapper.isRequired())
                resourceSchema.addRequiredItem(taxonomyPropertyMapper.getName());
            } else {
              Set<OWLClass> classesInSignature = superCls.getClassesInSignature();
              for (OWLClass cls : classesInSignature) {
                List<OWLNamedIndividual> individuals = EntitySearcher.getIndividuals(cls, context.getOntology())
                    .flatMap(Narrow.to(OWLNamedIndividual.class)).toList();
                taxonomyPropertyMapper = new TaxonomyPropertyMapper(context,
                    taxonomyName(nameResolver.resolve(cls)),
                    OntologyUtil.getDescription(cls, context.getOntology()), getLabel(cls),
                    individuals.stream()
                        .map(this::getLabel).toList(), taxonomyRestrictions);
                resourceSchema.addProperty(taxonomyPropertyMapper.getName(),
                    taxonomyPropertyMapper.getTaxonomySchemaObject());
                if (taxonomyPropertyMapper.isRequired())
                  resourceSchema.addRequiredItem(taxonomyPropertyMapper.getName());
              }
            }
          }
        }
      }
    }
    if (resourceSchema.getProperties() == null || resourceSchema.getProperties().isEmpty()) {
      logger.warning("No properties with " + OntologyConstants.apiLabel + " annotation found for: " + analyzedClass);
      List<OWLSubClassOfAxiom> all = Stream.of(superClassOfAxioms, subClassOfAxioms, taxonomyAx)
          .flatMap(Collection::stream).toList();
      if (!all.isEmpty()) {
        List<String> possible = all.stream()
            .map(owlSubClassOfAxiom -> owlSubClassOfAxiom.getSuperClass().toString()).toList();
        if (!possible.isEmpty()) {
          possible.forEach(s -> logger.warning("\tPossible property: " + s));
        }
      }
    }
    return resourceSchema;
  }

  private List<OWLSubClassOfAxiom> getTaxonomyAxioms(OWLClass analyzedClass) {
    Set<OWLSubClassOfAxiom> subAx = context.getOntology().getSubClassAxiomsForSubClass(analyzedClass);
    String schemaAnnotation = getSchemaAnnotation(context.getSchemaLabel());

    return subAx.stream().filter(ax -> ax.annotations()
        .anyMatch(annotation -> annotation.getValue().toString().equals(schemaAnnotation))).filter(ax -> {
      OWLClassExpression superCls = ax.getSuperClass();
      return !superCls.getObjectPropertiesInSignature().isEmpty() && (superCls.individualsInSignature()
          .anyMatch(individual -> !EntitySearcher.getObjectPropertyValues(individual, context.getOntology())
              .isEmpty()) || superCls.classesInSignature()
          .anyMatch(cls -> EntitySearcher.getIndividuals(cls, context.getOntology()).findAny().isPresent()));
    }).collect(Collectors.toList());
  }

  public String getSchemaName() {
    return nameResolver.resolve(cls);
  }

  private String getSchemaAnnotation(String schema) {
    return '"' + schema + '"' + "^^xsd:string";
  }

  private String taxonomyName(String taxonomy_name) {
    if (StringUtils.countMatches(taxonomy_name, "_") > 0) {
      return taxonomy_name.substring(taxonomy_name.lastIndexOf("_") + 1);
    }
    return taxonomy_name.substring(0, 1).toUpperCase() + taxonomy_name.substring(1);
  }

  private String getLabel(final OWLEntity entity) {
    return OntologyUtil.getTitle(entity, context.getOntology());
  }

  private Stream<OWLSubClassOfAxiom> getSuperClassAxioms(OWLClass analyzedClass,
                                                         @Nullable Set<OWLClass> ignoreClasses) {
    final Set<OWLClass> processedClasses = Optional.ofNullable(ignoreClasses).orElse(new HashSet<OWLClass>());
    final String schemaAnnotation = getSchemaAnnotation(context.getSchemaLabel());
    return context.getOntology().subClassAxiomsForSubClass(analyzedClass)
        .filter(WithAnnotation.of(OntologyConstants.apiLabel, context.getSchemaLabel()))
        .map(OWLSubClassOfAxiom::getSuperClass).filter(OWLClassExpression::isOWLClass).map(AsOWLClass::asOWLClass)
        .filter(Predicate.not(processedClasses::contains)).peek(processedClasses::add) // side effect
        .flatMap(context.getOntology()::subClassAxiomsForSubClass).flatMap(owlSubClassOfAxiom -> {
          final OWLClassExpression superClass = owlSubClassOfAxiom.getSuperClass();
          final List<OWLSubClassOfAxiom> superClassAxioms = new ArrayList<>();
          if (superClass.isOWLClass()) {
            getSuperClassAxioms(superClass.asOWLClass(), processedClasses).forEach(superClassAxioms::add);
          }
          if (owlSubClassOfAxiom.annotations()
              .anyMatch(owlAnnotation -> owlAnnotation.getValue().toString().equals(schemaAnnotation))) {
            superClassAxioms.add(owlSubClassOfAxiom);
          }
          return superClassAxioms.stream();
        });
  }

}

